import{_ as e,o as s,c as i,a2 as o}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Segurança","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/security.md","filePath":"concepts/security.md"}'),r={name:"concepts/security.md"};function n(t,a,l,d,c,p){return s(),i("div",null,[...a[0]||(a[0]=[o(`<h1 id="seguranca" tabindex="-1">Segurança <a class="header-anchor" href="#seguranca" aria-label="Permalink to &quot;Segurança&quot;">​</a></h1><h2 id="modelo-de-seguranca" tabindex="-1">Modelo de Segurança <a class="header-anchor" href="#modelo-de-seguranca" aria-label="Permalink to &quot;Modelo de Segurança&quot;">​</a></h2><p>O Torukr implementa múltiplas camadas de segurança:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Client[Cliente] --&gt;|JWT| API[API Server]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    API --&gt;|bcrypt| DB[(PostgreSQL)]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Controller --&gt;|mTLS| NodeRuntime</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    NodeRuntime --&gt;|Docker socket| Docker</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Secrets --&gt;|AES-256-GCM| DB</span></span></code></pre></div><h2 id="autenticacao-de-usuarios-jwt" tabindex="-1">Autenticação de Usuários (JWT) <a class="header-anchor" href="#autenticacao-de-usuarios-jwt" aria-label="Permalink to &quot;Autenticação de Usuários (JWT)&quot;">​</a></h2><ul><li>Senhas armazenadas com <strong>bcrypt</strong></li><li>Autenticação via JWT (HS256)</li><li>Tokens expiram conforme <code>JWT_EXPIRY_HOURS</code></li><li>O <code>JWT_SECRET</code> é validado: deve ter entropia suficiente</li></ul><h2 id="mtls-controller-↔-noderuntime" tabindex="-1">mTLS Controller ↔ NodeRuntime <a class="header-anchor" href="#mtls-controller-↔-noderuntime" aria-label="Permalink to &quot;mTLS Controller ↔ NodeRuntime&quot;">​</a></h2><p>Toda comunicação entre Controller e NodeRuntime usa <strong>mutual TLS</strong>:</p><ul><li>Ambos os lados apresentam certificados</li><li>Ambos os lados verificam o certificado do outro contra a CA raiz</li><li>Impede que processos não autorizados recebam instruções do Controller</li></ul><p>Veja <a href="/concepts/certificates.html">Certificados</a> para detalhes.</p><h2 id="criptografia-de-secrets-aes-256-gcm" tabindex="-1">Criptografia de Secrets (AES-256-GCM) <a class="header-anchor" href="#criptografia-de-secrets-aes-256-gcm" aria-label="Permalink to &quot;Criptografia de Secrets (AES-256-GCM)&quot;">​</a></h2><p>Secrets (senhas geradas automaticamente para Resources) são criptografados em repouso no banco de dados usando AES-256-GCM com a <code>TORUKR_MASTER_KEY</code>.</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Gerar master key segura</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TORUKR_MASTER_KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=$(openssl rand -base64 32)</span></span></code></pre></div><p>A master key nunca é armazenada no banco — apenas usada em memória para criptografar/decriptografar.</p><h2 id="rbac-controle-de-acesso-por-role" tabindex="-1">RBAC (Controle de Acesso por Role) <a class="header-anchor" href="#rbac-controle-de-acesso-por-role" aria-label="Permalink to &quot;RBAC (Controle de Acesso por Role)&quot;">​</a></h2><p>O Torukr tem uma estrutura de RBAC com:</p><ul><li><strong>Usuários</strong> — contas de acesso</li><li><strong>Roles</strong> — agrupam permissões</li><li><strong>Permissions</strong> — operações permitidas</li><li><strong>RoleBindings</strong> — associam roles a usuários</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Via API</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Criar role</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /api/v1/roles</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Criar permissão</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /api/v1/permissions</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Vincular permissão ao role</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /api/v1/roles/{id}/permissions</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Vincular role ao usuário</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /api/v1/users/{id}/roles</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Limitação Atual</p><p>O sistema de RBAC está implementado na camada de dados (repositórios e API), mas a verificação de permissões não está aplicada em todos os endpoints. Esta é uma limitação conhecida — veja <a href="/operations/known-limitations.html">Limitações Conhecidas</a>.</p></div><h2 id="security-headers" tabindex="-1">Security Headers <a class="header-anchor" href="#security-headers" aria-label="Permalink to &quot;Security Headers&quot;">​</a></h2><p>O middleware de segurança adiciona automaticamente:</p><ul><li><code>X-Content-Type-Options: nosniff</code></li><li><code>X-Frame-Options: DENY</code></li><li><code>X-XSS-Protection: 1; mode=block</code></li><li><code>Referrer-Policy: strict-origin-when-cross-origin</code></li></ul><h2 id="rate-limiting" tabindex="-1">Rate Limiting <a class="header-anchor" href="#rate-limiting" aria-label="Permalink to &quot;Rate Limiting&quot;">​</a></h2><p>Rate limiting por IP é aplicado em todas as rotas da API usando token bucket (<code>golang.org/x/time/rate</code>).</p><h2 id="validacao-do-banco-de-dados-em-producao" tabindex="-1">Validação do Banco de Dados em Produção <a class="header-anchor" href="#validacao-do-banco-de-dados-em-producao" aria-label="Permalink to &quot;Validação do Banco de Dados em Produção&quot;">​</a></h2><p>Quando <code>ENV=production</code>, o Torukr valida que o <code>DATABASE_DSN</code> usa conexão TLS com o PostgreSQL. Conexões sem TLS em produção são rejeitadas na inicialização.</p><h2 id="boas-praticas-de-seguranca" tabindex="-1">Boas Práticas de Segurança <a class="header-anchor" href="#boas-praticas-de-seguranca" aria-label="Permalink to &quot;Boas Práticas de Segurança&quot;">​</a></h2><h3 id="em-producao" tabindex="-1">Em Produção <a class="header-anchor" href="#em-producao" aria-label="Permalink to &quot;Em Produção&quot;">​</a></h3><ul><li><code>TORUKR_TLS_ENABLED=true</code> (obrigatório)</li><li><code>JWT_SECRET</code> com no mínimo 32 caracteres e alta entropia</li><li><code>TORUKR_MASTER_KEY</code> gerado com <code>openssl rand -base64 32</code></li><li>Chaves privadas (<code>*-key.pem</code>) com permissão <code>600</code></li><li><code>DATABASE_DSN</code> com <code>sslmode=require</code> ou <code>sslmode=verify-full</code></li><li><code>ENV=production</code> para ativar validações extras</li></ul><h3 id="nunca-faca" tabindex="-1">Nunca Faça <a class="header-anchor" href="#nunca-faca" aria-label="Permalink to &quot;Nunca Faça&quot;">​</a></h3><ul><li><code>TORUKR_TLS_INSECURE_SKIP_VERIFY=true</code> em produção</li><li>Commitar <code>*.pem</code> ou <code>.env</code> no git</li><li>Usar a master key de desenvolvimento em produção</li><li>Deixar a porta 9090 (NodeRuntime) exposta na internet sem firewall</li></ul><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><ul><li><a href="/concepts/certificates.html">Certificados e mTLS</a></li><li><a href="/setup/environment-variables.html">Variáveis de Ambiente</a></li><li><a href="/operations/production-readiness.html">Checklist de Produção</a></li></ul>`,33)])])}const m=e(r,[["render",n]]);export{u as __pageData,m as default};
